using System.IdentityModel.Tokens.Jwt; using System.Security.Claims; using System.Text; using Microsoft.AspNetCore.Authorization; using Microsoft.AspNetCore.Mvc; using Microsoft.IdentityModel.Tokens; using ValoraPesquisa.Application.Contracts;
namespace ValoraPesquisa.Api.Controllers;
[ApiController] public sealed class AuthController(IUserRepository users,IPasswordHasher hasher,IAuditService audit,IConfiguration cfg):ControllerBase{
 [HttpPost("auth/login")] public async Task<IActionResult> Login(LoginRequest r){ var cid=HttpContext.Items["CorrelationId"]?.ToString()??""; var u=await users.FindByEmailAsync(r.Email); if(u is null||!hasher.Verify(r.Password,u.PasswordHash)){ await audit.RecordAsync(null,null,"login_failed","user",null,cid,new{email=r.Email}); return Unauthorized(new{ok=false,code="INVALID_LOGIN",message="E-mail ou senha inválidos.",correlationId=cid}); } await users.UpdateLastLoginAsync(u.Id); await audit.RecordAsync(u.OrganizationId,u.Id,"login_success","user",u.Id,cid,new{u.Email,u.Role}); var key=new SymmetricSecurityKey(Encoding.UTF8.GetBytes(cfg["Jwt:Key"]??"dev-only-change-this-key-with-32-chars")); var claims=new[]{new Claim("user_id",u.Id.ToString()),new Claim("organization_id",u.OrganizationId?.ToString()??""),new Claim("role",u.Role),new Claim("email",u.Email)}; var jwt=new JwtSecurityToken(claims:claims,expires:DateTime.UtcNow.AddHours(8),signingCredentials:new SigningCredentials(key,SecurityAlgorithms.HmacSha256)); return Ok(new{ok=true,token=new JwtSecurityTokenHandler().WriteToken(jwt),user=new{u.Id,u.OrganizationId,u.Name,u.Email,u.Role,u.Status,u.LastLoginAt}}); }
 [Authorize, HttpPost("auth/logout")] public IActionResult Logout()=>Ok(new{ok=true});
 [Authorize, HttpGet("me")] public async Task<IActionResult> Me(){ var id=Guid.Parse(User.FindFirstValue("user_id")!); var u=await users.FindByIdAsync(id); return Ok(new{ok=true,user=u is null?null:new{u.Id,u.OrganizationId,u.Name,u.Email,u.Role,u.Status,u.Phone,u.LastLoginAt}}); }
} public record LoginRequest(string Email,string Password);
